args.sparql:
SELECT ?club ?clubLabel WHERE {
  wd:Q151269 p:P54 ?membership .
  ?membership ps:P54 ?club .
  ?membership pq:P580 ?start .
  ?membership pq:P582 ?end .
  FILTER (?start <= "2020-12-31T23:59:59Z"^^xsd:dateTime)
  FILTER (?end >= "2020-01-01T00:00:00Z"^^xsd:dateTime)
  OPTIONAL { ?club rdfs:label ?clubLabel . FILTER(LANG(?clubLabel) = "en") }
}

